// Mutation with cache invalidation
const queryClient = useQueryClient();
const { mutate: updateUser } = useMutation({
  mutationFn: (data) => fetch(`/api/users/${userId}`, { method: 'PUT', body: JSON.stringify(data) }),
  onSuccess: () => {
    // Invalidate and refetch the user query
    queryClient.invalidateQueries({ queryKey: ['user', userId] });
  },
  onMutate: async (newData) => {
    // Optimistic update
    await queryClient.cancelQueries({ queryKey: ['user', userId] });
    const prev = queryClient.getQueryData(['user', userId]);
    queryClient.setQueryData(['user', userId], old => ({ ...old, ...newData }));
    return { prev }; // For rollback
  },
  onError: (err, newData, context) => {
    queryClient.setQueryData(['user', userId], context.prev); // Rollback
  },
});

