// Compound Component Pattern
const SelectContext = createContext(null);

function Select({ children, value, onChange }) {
  return (
    <SelectContext.Provider value={{ value, onChange }}>
      <div role="listbox">{children}</div>
    </SelectContext.Provider>
  );
}

Select.Option = function Option({ value, children }) {
  const { value: selected, onChange } = useContext(SelectContext);
  const isSelected = selected === value;

  return (
    <div
      role="option"
      aria-selected={isSelected}
      onClick={() => onChange(value)}
      className={isSelected ? 'selected' : ''}
    >
      {children}
    </div>
  );
};

// Flexible consumer API:
<Select value={country} onChange={setCountry}>
  <Select.Option value="in">India 🇮🇳</Select.Option>
  <Select.Option value="us">USA 🇺🇸</Select.Option>
  {/* Consumer controls layout, library controls behavior */}
</Select>

