// useEventCallback — stable reference, always fresh value
function useEventCallback<T extends (...args: any[]) => any>(fn: T): T {
  const ref = useRef<T>(fn);
  useLayoutEffect(() => { ref.current = fn; }); // Always sync
  return useCallback((...args) => ref.current(...args), []) as T;
}

// useControllable — works as controlled OR uncontrolled
function useControllable<T>(
  controlledValue: T | undefined,
  onChange: ((v: T) => void) | undefined,
  defaultValue: T
): [T, (v: T) => void] {
  const [internal, setInternal] = useState(defaultValue);
  const isControlled = controlledValue !== undefined;
  const value = isControlled ? controlledValue : internal;

  const setValue = useEventCallback((next: T) => {
    if (!isControlled) setInternal(next);
    onChange?.(next);
  });

  return [value, setValue];
}

// Usage in a component that works both ways:
function Toggle({ checked, onCheckedChange, defaultChecked = false }) {
  const [isOn, setIsOn] = useControllable(checked, onCheckedChange, defaultChecked);
  return <button onClick={() => setIsOn(!isOn)}>{isOn ? 'ON' : 'OFF'}</button>;
}

