// Streaming SSR (React 18+):
import { renderToPipeableStream } from 'react-dom/server';

const { pipe, abort } = renderToPipeableStream(<App />, {
  // Critical JS chunks to load first:
  bootstrapScripts: ['/static/js/main.js'],

  // Once the shell (above all Suspense boundaries) is ready:
  onShellReady() {
    res.statusCode = 200;
    res.setHeader('Content-Type', 'text/html');
    pipe(res); // Stream HTML directly to response!
  },

  onError(error) {
    console.error(error);
    res.statusCode = 500;
  }
});

