// Next.js App Router: time-based revalidation
async function ProductPage({ params }) {
  // Revalidate every 60 seconds (ISR):
  const product = await fetch(`/api/products/${params.id}`, {
    next: { revalidate: 60 } // CDN caches for 60s
  }).then(r => r.json());

  return <Product data={product} />;
}

// Tag-based invalidation (on-demand ISR):
async function getProduct(id) {
  return fetch(`/api/products/${id}`, {
    next: { tags: [`product-${id}`, 'products'] } // Cache tags
  });
}

// Webhook route (called when product updates in CMS):
export async function POST(request) {
  const { productId } = await request.json();

  // Invalidate just this product's cache:
  revalidateTag(`product-${productId}`);

  // OR invalidate all products:
  revalidatePath('/products', 'layout');

  return Response.json({ revalidated: true });
}

// Focus trap in Modal (accessibility requirement):
import { createFocusTrap } from 'focus-trap';

function Modal({ isOpen, onClose, children }) {
  const modalRef = useRef(null);

  useEffect(() => {
    if (!isOpen) return;
    // Trap focus inside modal
    const trap = createFocusTrap(modalRef.current, {
      onDeactivate: onClose,
      initialFocus: '.modal-title', // Focus first meaningful element
    });
    trap.activate();
    return () => trap.deactivate(); // Release on close
  }, [isOpen]);

  return (
    <div
      ref={modalRef}
      role="dialog"
      aria-modal="true"
      aria-labelledby="modal-title"
    >
      <h2 id="modal-title" className="modal-title">Confirm Action</h2>
      {children}
      <button onClick={onClose}>Cancel</button>
    </div>
  );
}

// ARIA Live Region for toast notifications:
function ToastContainer({ toasts }) {
  return (
    <div
      aria-live="polite"  // 'assertive' for errors
      aria-atomic="false" // Announce each toast individually
      className="visually-hidden" // Off-screen, screen reader only
    >
      {toasts.map(t => <p key={t.id}>{t.message}</p>)}
    </div>
  );
}

